if (! function_exists('image_comparator')) {
    function image_comparator($image_a, $image_b, $threshold = null, $output_diff = null, $filename = null, $timeout = null)
    {
        $image_a = $image_a ?? '';
        $image_b = $image_b ?? '';
        $threshold = $threshold ?? 10;
        $threshold = max(0, min(255, (int)$threshold));
        $output_diff = $output_diff ?? true;
        $filename = $filename ?? '';

        if (empty($image_a) || empty($image_b)) {
            return ['error' => 'Both image_a and image_b paths are required.'];
        }

        $start = microtime(true);

        // Resolve paths
        $root = getcwd();
        $resolve = function($path) use ($root) {
            if (strpos($path, DIRECTORY_SEPARATOR) !== 0 && strpos($path, ':') === false) {
                $candidate = $root . DIRECTORY_SEPARATOR . $path;
                if (file_exists($candidate)) return $candidate;
                $workspace = $root . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
                $candidate2 = $workspace . DIRECTORY_SEPARATOR . basename($path);
                if (file_exists($candidate2)) return $candidate2;
                return $candidate;
            }
            return $path;
        };

        $path_a = $resolve($image_a);
        $path_b = $resolve($image_b);

        if (!file_exists($path_a)) {
            return ['error' => 'Image A not found: ' . $image_a];
        }
        if (!file_exists($path_b)) {
            return ['error' => 'Image B not found: ' . $image_b];
        }

        // Load images
        $im_a = @imagecreatefromstring(file_get_contents($path_a));
        $im_b = @imagecreatefromstring(file_get_contents($path_b));

        if (!$im_a) {
            return ['error' => 'Cannot load Image A as an image. Supported: JPEG, PNG, GIF, WEBP, BMP.'];
        }
        if (!$im_b) {
            return ['error' => 'Cannot load Image B as an image. Supported: JPEG, PNG, GIF, WEBP, BMP.'];
        }

        $w_a = imagesx($im_a);
        $h_a = imagesy($im_a);
        $w_b = imagesx($im_b);
        $h_b = imagesy($im_b);

        // Get image info
        $info_a = [];
        $info_b = [];
        $fi = finfo_open(FILEINFO_MIME_TYPE);
        if ($fi) {
            $info_a['mime'] = finfo_file($fi, $path_a);
            $info_b['mime'] = finfo_file($fi, $path_b);
            finfo_close($fi);
        }
        $info_a['dimensions'] = $w_a . 'x' . $h_a;
        $info_b['dimensions'] = $w_b . 'x' . $h_b;
        $info_a['file_size'] = filesize($path_a);
        $info_b['file_size'] = filesize($path_b);

        // Compare overlapping area
        $cmp_w = min($w_a, $w_b);
        $cmp_h = min($h_a, $h_b);

        $total_pixels = $cmp_w * $cmp_h;
        $diff_pixels = 0;
        $mse_sum = 0.0;
        $max_diff = 0.0;

        $diff_im = null;
        if ($output_diff) {
            $diff_im = imagecreatetruecolor($cmp_w, $cmp_h);
            // Fill with black
            imagefill($diff_im, 0, 0, imagecolorallocate($diff_im, 0, 0, 0));
        }

        $diff_regions = [];

        for ($y = 0; $y < $cmp_h; $y++) {
            for ($x = 0; $x < $cmp_w; $x++) {
                $rgb_a = imagecolorat($im_a, $x, $y);
                $r_a = ($rgb_a >> 16) & 0xFF;
                $g_a = ($rgb_a >> 8) & 0xFF;
                $b_a = $rgb_a & 0xFF;
                
                $rgb_b = imagecolorat($im_b, $x, $y);
                $r_b = ($rgb_b >> 16) & 0xFF;
                $g_b = ($rgb_b >> 8) & 0xFF;
                $b_b = $rgb_b & 0xFF;
                
                $dr = abs($r_a - $r_b);
                $dg = abs($g_a - $g_b);
                $db = abs($b_a - $b_b);
                
                $max_diff_ch = max($dr, $dg, $db);
                if ($max_diff_ch > $max_diff) $max_diff = $max_diff_ch;
                
                $diff = ($dr > $threshold || $dg > $threshold || $db > $threshold);
                
                if ($diff) {
                    $diff_pixels++;
                    $mse_sum += ($dr * $dr + $dg * $dg + $db * $db) / 3.0;
                    
                    if ($diff_im) {
                        // Red highlight for differing pixels
                        $red = imagecolorallocate($diff_im, 255, 0, 0);
                        imagesetpixel($diff_im, $x, $y, $red);
                    }
                    
                    // Record diff regions
                    $region_key = (int)($x / 20) . '_' . (int)($y / 20);
                    if (!isset($diff_regions[$region_key])) {
                        $diff_regions[$region_key] = ['count' => 0, 'x' => $x, 'y' => $y];
                    }
                    $diff_regions[$region_key]['count']++;
                } elseif ($diff_im) {
                    // Copy original pixel for non-diff areas
                    $gray = imagecolorallocate($diff_im, $r_a, $g_a, $b_a);
                    imagesetpixel($diff_im, $x, $y, $gray);
                }
            }
        }

        $pct_diff = $total_pixels > 0 ? round($diff_pixels / $total_pixels * 100, 4) : 0;
        $mse = $total_pixels > 0 ? round($mse_sum / $total_pixels, 4) : 0;
        $psnr = ($mse > 0) ? round(10 * log10(255 * 255 / $mse), 2) : ($total_pixels > 0 ? 'Infinity (identical)' : 'N/A');

        // Dimensions difference
        $size_info = 'identical';
        if ($w_a !== $w_b || $h_a !== $h_b) {
            $size_info = "A: {$w_a}x{$h_a}, B: {$w_b}x{$h_b} (comparing overlapping {$cmp_w}x{$cmp_h})";
        }

        $diff_file = null;
        if ($diff_im && $output_diff) {
            $workspace = getcwd() . DIRECTORY_SEPARATOR . 'storage' . DIRECTORY_SEPARATOR . 'agent' . DIRECTORY_SEPARATOR . 'workspace';
            if (!is_dir($workspace)) @mkdir($workspace, 0755, true);
            
            if (empty($filename)) {
                $ts = date('Ymd_His');
                $name_a = pathinfo($image_a, PATHINFO_FILENAME);
                $name_b = pathinfo($image_b, PATHINFO_FILENAME);
                $filename = "diff_{$name_a}_vs_{$name_b}_{$ts}.png";
            }
            if (!str_ends_with($filename, '.png')) $filename .= '.png';
            $filename = preg_replace('/[^a-zA-Z0-9_.-]/', '_', $filename);
            
            $out_path = $workspace . DIRECTORY_SEPARATOR . $filename;
            imagepng($diff_im, $out_path);
            $diff_file = 'storage/agent/workspace/' . $filename;
            imagedestroy($diff_im);
        }

        imagedestroy($im_a);
        imagedestroy($im_b);

        $elapsed = round(microtime(true) - $start, 4);

        return [
            'success' => true,
            'image_a' => [
                'path' => $image_a,
                'dimensions' => $info_a['dimensions'],
                'mime' => $info_a['mime'] ?? 'unknown',
                'file_size' => $info_a['file_size'],
            ],
            'image_b' => [
                'path' => $image_b,
                'dimensions' => $info_b['dimensions'],
                'mime' => $info_b['mime'] ?? 'unknown',
                'file_size' => $info_b['file_size'],
            ],
            'comparison' => [
                'overlapping_area' => $cmp_w . 'x' . $cmp_h,
                'total_pixels_compared' => $total_pixels,
                'different_pixels' => $diff_pixels,
                'percent_different' => $pct_diff,
                'identical' => ($diff_pixels === 0),
                'mse' => $mse,
                'psnr' => $psnr,
                'max_channel_diff' => $max_diff,
                'threshold' => $threshold,
                'dimension_compare' => $size_info,
            ],
            'diff_image' => $diff_file,
            'elapsed_seconds' => $elapsed,
        ];
    }
